mapper.delete:
DELETE FROM FOODM
WHERE foodCategory_Id IN (
SELECT foodCategory_Id
FROM FOODC
WHERE foodCategory = #{foodCategory}
)

mapper.select:
SELECT * FROM (
SELECT ROW_NUMBER() OVER (ORDER BY ${orderBy}) AS rn,
f.foodMaterial_Id AS foodMaterialId, f.foodMaterialName, c.foodCategory,
f.foodMaterialCount, f.foodMaterialCountAll, f.foodMaterialPrice,
f.vender, f.incomeDate, f.expirationDate, f.foodMaterialType
FROM FOODM f
JOIN FOODC c ON f.foodCategory_Id = c.foodCategory_Id
WHERE f.bId = #{bId}
)
WHERE rn BETWEEN #{startRow} AND #{endRow}

mapper.delete:
DELETE FROM FOODM
WHERE foodMaterial_Id = #{foodMaterialId}
AND bId = #{bId}
